<?php
namespace Zclone\controllers; use Zclone\Core\Database; use Zclone\Core\Request; use Zclone\Core\Response; use Zclone\services\BuildingService; use Zclone\services\FleetService; final class GameApiController { public function __construct(private Database $db, private BuildingService $buildings, private FleetService $fleets) {} public function state(Request $r): void { $planet=$this->db->one('select * from planets where user_id=? order by id limit 1',[$r->userId()]); $queue=$planet?$this->db->all('select * from build_queue where planet_id=? and completed_at is null order by finish_at',[$planet['id']]):[]; Response::json(['planet'=>$planet,'queue'=>$queue,'serverTime'=>time()]); } public function build(Request $r): void { $p=$this->db->one('select id from planets where user_id=? order by id limit 1',[$r->userId()]); $this->buildings->enqueue((int)$p['id'], (string)$r->input('type')); Response::json(['ok'=>true]); } public function dispatchFleet(Request $r): void { $p=$this->db->one('select id from planets where user_id=? order by id limit 1',[$r->userId()]); $id=$this->fleets->dispatch($r->userId(),(int)$p['id'],['galaxy'=>(int)$r->input('galaxy'),'system'=>(int)$r->input('system'),'slot'=>(int)$r->input('slot')],(string)$r->input('mission','spy'),(array)$r->input('ships',[])); Response::json(['fleet_id'=>$id]); } }
